insert into "T_ALERT_RULE" ("ID","NAME","MEMO","PROCESSOR","PARAMETERS","GROUPS","TABLE_NAME","CODE","RULE_DESC","STATUS","RULE_TYPE") values (1, '连接丢失', '设备连接异常', 'com.dm.cn.base.entity.vo.DeviceGatherInfoVO', '{"duration":"0","durationUnit":"m","fatalStatus":true,"errorStatus":"1","valueUnit":"none","configType":"on-off","memo":"设备连接丢失","column":"status","logic":"eq"}', '设备状态', 't_device', 'device_offline', '<p>确认主机的连接状态是否正常。</p>', 'yes','0');
insert into "T_ALERT_RULE" ("ID","NAME","MEMO","PROCESSOR","PARAMETERS","GROUPS","TABLE_NAME","CODE","RULE_DESC","STATUS","RULE_TYPE") values (2, '设备CPU使用率过高', '当前CPU使用率【{cur}】过高，已超过{level}级别告警阈值{levelVal}', 'com.dm.cn.base.entity.vo.DeviceGatherInfoVO', '{"duration":"3","durationUnit":"m","fatal":90,"fatalStatus":true,"warning":70,"warningStatus":true,"valueUnit":"percent","configType":"on-off-value-time","memo":"主机CPU使用率 超过","column":"cpuUsage","logic":"gt"}', '资源监控', 't_device', 'device_cpu', '<p>确认CPU的使用率（所有处理器），帮助管理员了解主机的CPU负载情况。</p><p>标准经验为70%以下的使用率是健康的。</p>', 'yes','0');
insert into "T_ALERT_RULE" ("ID","NAME","MEMO","PROCESSOR","PARAMETERS","GROUPS","TABLE_NAME","CODE","RULE_DESC","STATUS","RULE_TYPE") values (3, '设备内存使用率过高', '当前内存使用率【{cur}】过高，已超过{level}级别告警阈值{levelVal}', 'com.dm.cn.base.entity.vo.DeviceGatherInfoVO', '{"duration":"3","durationUnit":"m","fatal":90,"fatalStatus":true,"warning":70,"warningStatus":true,"valueUnit":"percent","configType":"on-off-value-time","memo":"主机内存使用率 超过","column":"memUsage","logic":"gt"}', '资源监控', 't_device', 'device_mem', '<p>确认内存使用率，帮助管理员了解主机的内存负载情况。</p><p>使用率过高会导致系统性能降低或无法继续运行。</p>', 'yes','0');
insert into "T_ALERT_RULE" ("ID","NAME","MEMO","PROCESSOR","PARAMETERS","GROUPS","TABLE_NAME","CODE","RULE_DESC","STATUS","RULE_TYPE") values (4, '设备磁盘空间使用率过高', '当前磁盘分区使用率【{cur}】过高，已超过{level}级别告警阈值{levelVal}', 'com.dm.cn.base.entity.vo.DeviceGatherInfoVO', '{"duration":"0","durationUnit":"m","fatal":90,"fatalStatus":true,"warning":70,"warningStatus":true,"valueUnit":"percent","configType":"on-off-value-time","memo":"设备的磁盘空间使用率 超过","column":"diskUsage","logic":"gt"}', '资源监控', 't_device', 'device_disk', '<p>确认主机的磁盘空间使用率，帮助管理员判断空间不足的风险。</p>', 'yes','0');
insert into "T_ALERT_RULE" ("ID","NAME","MEMO","PROCESSOR","PARAMETERS","GROUPS","TABLE_NAME","CODE","RULE_DESC","STATUS","RULE_TYPE") values (5, '设备网络下行速率过高', '当前网络下行速率【{cur}】过高，已超过{level}级别告警阈值{levelVal}', 'com.dm.cn.base.entity.vo.DeviceGatherInfoVO', '{"duration":"3","durationUnit":"m","fatal":600,"fatalStatus":true,"warning":400,"warningStatus":true,"valueUnit":"mb_s","configType":"on-off-value-time","memo":"设备网络下行速率 超过","column":"networkInput","logic":"gt"}', '资源监控', 't_device', 'network_input', null, 'yes','0');
insert into "T_ALERT_RULE" ("ID","NAME","MEMO","PROCESSOR","PARAMETERS","GROUPS","TABLE_NAME","CODE","RULE_DESC","STATUS","RULE_TYPE") values (6, '设备网络上行速率过高', '当前网络上行速率【{cur}】过高，已超过{level}级别告警阈值{levelVal}', 'com.dm.cn.base.entity.vo.DeviceGatherInfoVO', '{"duration":"3","durationUnit":"m","fatal":600,"fatalStatus":true,"warning":400,"warningStatus":true,"valueUnit":"mb_s","configType":"on-off-value-time","memo":"设备网络上行速率 超过","column":"networkOutput","logic":"gt"}', '资源监控', 't_device', 'network_output', null, 'yes','0');
